package ru.memearena.scout.domain; import jakarta.persistence.*; import java.time.*; import java.util.*;
@Entity @Table(name="meme_prediction") public class MemePrediction{ @Id private UUID id; @Column(name="user_id") private UUID userId; @Column(name="meme_id") private UUID memeId; @Column(name="vote_id") private UUID voteId; @Enumerated(EnumType.STRING) private PredictionStatus status; @Column(name="battles_before_vote") private long battlesBeforeVote; @Column(name="meme_rating_before_vote") private int memeRatingBeforeVote; @Column(name="predicted_at") private Instant predictedAt; @Column(name="resolved_at") private Instant resolvedAt; @Column(name="points_awarded") private int pointsAwarded; @Column(name="resolution_reason") private String resolutionReason; @Column(name="created_at") private Instant createdAt; @Column(name="updated_at") private Instant updatedAt; protected MemePrediction(){} public MemePrediction(UUID id,UUID userId,UUID memeId,UUID voteId,long battles,int rating,Instant now){this.id=id;this.userId=userId;this.memeId=memeId;this.voteId=voteId;this.status=PredictionStatus.PENDING;this.battlesBeforeVote=battles;this.memeRatingBeforeVote=rating;this.predictedAt=now;this.createdAt=now;this.updatedAt=now;} public UUID getId(){return id;} public UUID getUserId(){return userId;} public UUID getMemeId(){return memeId;} public PredictionStatus getStatus(){return status;} public long getBattlesBeforeVote(){return battlesBeforeVote;} public int getMemeRatingBeforeVote(){return memeRatingBeforeVote;} public Instant getPredictedAt(){return predictedAt;} public Instant getResolvedAt(){return resolvedAt;} public int getPointsAwarded(){return pointsAwarded;} public void resolve(PredictionStatus s,int points,String reason,Instant now){if(status!=PredictionStatus.PENDING)return;status=s;pointsAwarded=points;resolutionReason=reason;resolvedAt=now;updatedAt=now;} }
